/* parsuna_rt: header-only runtime shared by every C parser generated by
 * parsuna.
 *
 * End users don't see this file — generated `<stem>.h` exposes its own
 * `<stem>_*` API, and the matching `<stem>.c` includes this header
 * internally so the whole runtime folds into the same translation unit
 * as the state machine. All names here are therefore plain (no prefix):
 * every symbol is `static inline` at file scope, so collisions only
 * matter within the one generated TU, and the generator takes care to
 * avoid them.
 */
#ifndef PARSUNA_RT_H
#define PARSUNA_RT_H

#include <stddef.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ---------- types ---------- */

/* Source position: byte offset plus 1-based line/column. */
typedef struct { uint32_t offset, line, column; } Pos;

/* Half-open span [start, end) over the source. */
typedef struct { Pos start, end; } Span;

/* A lexed token: kind, span, and the matched text.
 *
 * `text` and `text_len` describe the matched bytes. In *reader* mode
 * (parser_init_from_read_fn) `text` is a fresh allocation owned by the
 * parser until the next call to parser_next, and is NUL-terminated.
 * In *string* mode (parser_init_from_string) `text` points directly into
 * the caller's source buffer — zero-copy and NOT NUL-terminated; read
 * exactly `text_len` bytes. Use `text_len` in both modes. */
typedef struct { int kind; Span span; char *text; size_t text_len; } Token;

/* A recoverable parse or lex error. `message` is owned by the parser
 * until the next call to parser_next. */
typedef struct { char *message; Span span; } Error;

/* Event discriminator: ENTER/EXIT delimit a rule subtree, TOKEN carries
 * a consumed token, ERROR is a recoverable diagnostic. */
typedef enum {
    EV_ENTER,
    EV_EXIT,
    EV_TOKEN,
    EV_ERROR
} EventTag;

/* Single parse event; inspect `tag` to decide which payload field to read. */
typedef struct {
    EventTag tag;
    int rule;
    Pos pos;
    Token token;
    Error error;
} Event;

/* Reader callback: fill up to `max` bytes into `out`, return number of
 * bytes written (0 for EOF, negative to signal an error). */
typedef int (*ReadFn)(void *ctx, char *out, int max);

/* Packed lexer DFA. State 0 is the dead sink; real states start at 1. */
typedef struct {
    uint32_t start;
    const uint32_t *trans;   /* states * 256 entries */
    const uint16_t *accept;
} DfaConfig;

/* Sentinel value that marks end of `sync` / FIRST sequence arrays.
 * Using -2 avoids colliding with any real token-kind id (EOF = 0,
 * ERROR = -1, grammar tokens >= 1). */
#define SENTINEL (-2)

/* State id meaning "the parser has terminated". Reserved: real states
 * start at 1, so 0 is unambiguous. */
#define TERMINATED 0

/* ---------- monomorphization hooks ----------
 * The including translation unit (the generated `<stem>.c`) must supply
 * four things BEFORE including this header so the runtime can call them
 * directly instead of going through a Config vtable:
 *
 *   #define PARSUNA_K            <lookahead depth>
 *   #define PARSUNA_EOF_KIND     <token-kind id for EOF>
 *   #define PARSUNA_ERROR_KIND   <token-kind id for lexer ERROR>
 *
 * plus file-scope definitions of:
 *
 *   static int            is_skip(int kind);
 *   static void           drive(Parser *p);
 *   static const DfaConfig dfa_config;
 *
 * The generated .c provides all of these. `is_skip`, `drive`, and
 * `dfa_config` are forward-declared below so the runtime's inline
 * functions can reference them; the compiler links every reference to
 * the later real definitions within the same translation unit. */
#ifndef PARSUNA_K
#  error "define PARSUNA_K before including parsuna_rt.h"
#endif
#ifndef PARSUNA_EOF_KIND
#  error "define PARSUNA_EOF_KIND before including parsuna_rt.h"
#endif
#ifndef PARSUNA_ERROR_KIND
#  error "define PARSUNA_ERROR_KIND before including parsuna_rt.h"
#endif

struct Parser;  /* fwd decl */
static int  is_skip(int kind);
static void drive(struct Parser *p);
static const DfaConfig dfa_config;   /* tentative def; generator supplies the real one */

/* Internal queue element; matches Event layout. */
typedef Event EvQueued;

/* Parser state. */
typedef struct Parser {
    /* lexer state */
    ReadFn read_fn; void *read_ctx;
    char *buf; size_t buf_len, buf_cap, buf_pos;
    int eof;
    /* When set, `buf` is borrowed from the caller (parser_init_from_string):
     * no realloc, no memmove compaction, no per-token text allocation, and
     * parser_destroy does not free it. */
    int borrow_buf;
    uint32_t offset, line, col;

    /* parser state */
    Token look_buf[PARSUNA_K];   /* inline; size is a compile-time constant */
    Pos   prev_end;
    int   state;
    int   *ret; size_t ret_len, ret_cap;
    EvQueued *queue; size_t queue_len, queue_cap;

    Token *pending_skips; size_t pending_skips_len, pending_skips_cap;
    int eof_checked;

    /* ownership of last-yielded event strings until the next call */
    Token last_token;
    Error last_error;
} Parser;

/* ---------- UTF-8 helper ---------- */

/* Write the codepoint at src[at..end] to *cp and return the byte length
 * consumed (1..4), or 1 if the byte is a continuation/garbage (advancing
 * by one is the right recovery step). */
static inline size_t utf8_decode(const char *src, size_t at, size_t end, uint32_t *cp) {
    if (at >= end) { *cp = 0; return 0; }
    unsigned char b0 = (unsigned char)src[at];
    if (b0 < 0x80) { *cp = b0; return 1; }
    if (b0 < 0xC0) { *cp = b0; return 1; }
    if (b0 < 0xE0) {
        if (at + 1 >= end) { *cp = b0; return 1; }
        *cp = ((b0 & 0x1F) << 6) | ((unsigned char)src[at + 1] & 0x3F);
        return 2;
    }
    if (b0 < 0xF0) {
        if (at + 2 >= end) { *cp = b0; return 1; }
        *cp = ((b0 & 0x0F) << 12) | (((unsigned char)src[at + 1] & 0x3F) << 6) | ((unsigned char)src[at + 2] & 0x3F);
        return 3;
    }
    if (at + 3 >= end) { *cp = b0; return 1; }
    *cp = ((b0 & 0x07) << 18)
        | (((unsigned char)src[at + 1] & 0x3F) << 12)
        | (((unsigned char)src[at + 2] & 0x3F) << 6)
        | ((unsigned char)src[at + 3] & 0x3F);
    return 4;
}

static inline int set_contains(const int *set, int k) {
    for (; *set != SENTINEL; set++) if (*set == k) return 1;
    return 0;
}

/* ---------- buffer / lexer helpers ---------- */

#define CHUNK 16384

static inline int lex_read_more(Parser *p) {
    if (p->eof) return 0;
    if (p->buf_cap - p->buf_len < CHUNK) {
        size_t new_cap = p->buf_cap ? p->buf_cap * 2 : (CHUNK * 2);
        while (new_cap - p->buf_len < CHUNK) new_cap *= 2;
        p->buf = (char*)realloc(p->buf, new_cap);
        p->buf_cap = new_cap;
    }
    int n = p->read_fn(p->read_ctx, p->buf + p->buf_len, (int)(p->buf_cap - p->buf_len));
    if (n <= 0) { p->eof = 1; return 0; }
    p->buf_len += (size_t)n;
    return 1;
}

static inline void lex_ensure(Parser *p, size_t want) {
    while (!p->eof && p->buf_len - p->buf_pos < want) {
        if (!lex_read_more(p)) break;
    }
}

/* Fast-path for pure ASCII non-newline slices; byte-by-byte walk when
 * the slice contains newlines or multi-byte UTF-8 sequences. */
static inline void lex_advance(Parser *p, size_t n) {
    size_t end = p->buf_pos + n;
    int needs_walk = 0;
    for (size_t k = p->buf_pos; k < end; k++) {
        unsigned char b = (unsigned char)p->buf[k];
        if (b == '\n' || b >= 0x80) { needs_walk = 1; break; }
    }
    if (!needs_walk) {
        p->col += (uint32_t)n;
        p->offset += (uint32_t)n;
        p->buf_pos = end;
    } else {
        while (p->buf_pos < end) {
            unsigned char b = (unsigned char)p->buf[p->buf_pos];
            p->buf_pos++; p->offset++;
            if (b == '\n') { p->line++; p->col = 1; }
            else if ((b & 0xC0) != 0x80) p->col++;
        }
    }
    /* Borrowed buffers must stay pinned so token texts remain valid; only
     * owned streaming buffers get compacted. */
    if (!p->borrow_buf && p->buf_pos > 65536) {
        memmove(p->buf, p->buf + p->buf_pos, p->buf_len - p->buf_pos);
        p->buf_len -= p->buf_pos;
        p->buf_pos = 0;
    }
}

static inline void longest_match(Parser *p, int *best_kind, int *best_len) {
    const DfaConfig *dfa = &dfa_config;
    for (;;) {
        uint32_t state = dfa->start;
        size_t pos = p->buf_pos;
        int bl = 0;
        int bk = PARSUNA_ERROR_KIND;
        while (pos < p->buf_len) {
            uint32_t next = dfa->trans[state * 256 + (unsigned char)p->buf[pos]];
            if (next == 0) break;
            pos++;
            state = next;
            uint16_t acc = dfa->accept[state];
            if (acc != 0) {
                bl = (int)(pos - p->buf_pos);
                bk = (int)acc;
            }
        }
        if (!p->eof && pos == p->buf_len && bl > 0) {
            if (lex_read_more(p)) continue;
        }
        *best_kind = bk; *best_len = bl;
        return;
    }
}

/* Build a token's text field. In borrow mode point into the source buffer
 * (zero-copy, not NUL-terminated). In owned mode malloc + memcpy + NUL. */
static inline char *make_text(Parser *p, size_t n) {
    if (p->borrow_buf) return p->buf + p->buf_pos;
    char *text = (char*)malloc(n + 1);
    memcpy(text, p->buf + p->buf_pos, n); text[n] = 0;
    return text;
}

static inline Token lex_next(Parser *p) {
    lex_ensure(p, CHUNK);
    if (p->buf_len - p->buf_pos == 0) {
        Pos pos = { p->offset, p->line, p->col };
        Token t = { PARSUNA_EOF_KIND, { pos, pos }, NULL, 0 };
        return t;
    }
    int best_kind, best_len;
    longest_match(p, &best_kind, &best_len);
    Pos start = { p->offset, p->line, p->col };
    if (best_len == 0) {
        uint32_t cp; size_t n = utf8_decode(p->buf, p->buf_pos, p->buf_len, &cp);
        if (n == 0) n = 1;
        char *text = make_text(p, n);
        lex_advance(p, n);
        Pos end = { p->offset, p->line, p->col };
        Token t = { PARSUNA_ERROR_KIND, { start, end }, text, n };
        return t;
    }
    char *text = make_text(p, (size_t)best_len);
    lex_advance(p, (size_t)best_len);
    Pos end = { p->offset, p->line, p->col };
    Token t = { best_kind, { start, end }, text, (size_t)best_len };
    return t;
}

/* ---------- queue / return stack / pending skips ---------- */

static inline void ret_push(Parser *p, int s) {
    if (p->ret_len == p->ret_cap) {
        p->ret_cap = p->ret_cap ? p->ret_cap * 2 : 8;
        p->ret = (int*)realloc(p->ret, p->ret_cap * sizeof(int));
    }
    p->ret[p->ret_len++] = s;
}

static inline void queue_push(Parser *p, EvQueued e) {
    if (p->queue_len == p->queue_cap) {
        p->queue_cap = p->queue_cap ? p->queue_cap * 2 : 8;
        p->queue = (EvQueued*)realloc(p->queue, p->queue_cap * sizeof(EvQueued));
    }
    p->queue[p->queue_len++] = e;
}

static inline void pending_push(Parser *p, Token t) {
    if (p->pending_skips_len == p->pending_skips_cap) {
        p->pending_skips_cap = p->pending_skips_cap ? p->pending_skips_cap * 2 : 4;
        p->pending_skips = (Token*)realloc(p->pending_skips, p->pending_skips_cap * sizeof(Token));
    }
    p->pending_skips[p->pending_skips_len++] = t;
}

/* Drain skip tokens whose end offset is <= off. Called before every
 * event so whitespace/comments appear in source order. */
static inline void flush_skips_before(Parser *p, uint32_t off) {
    size_t i = 0;
    while (i < p->pending_skips_len && p->pending_skips[i].span.end.offset <= off) {
        EvQueued e = {0};
        e.tag = EV_TOKEN;
        e.token = p->pending_skips[i];
        queue_push(p, e);
        i++;
    }
    if (i > 0) {
        memmove(p->pending_skips, p->pending_skips + i, (p->pending_skips_len - i) * sizeof *p->pending_skips);
        p->pending_skips_len -= i;
    }
}

static inline Token pump_token(Parser *p) {
    for (;;) {
        Token t = lex_next(p);
        if (is_skip(t.kind)) { pending_push(p, t); continue; }
        return t;
    }
}

static inline void advance_look(Parser *p) {
    /* With PARSUNA_K as a compile-time constant, the shift loop trivially
     * unrolls (k=1 degenerates to a single pump). */
    for (int i = 0; i < PARSUNA_K - 1; i++) p->look_buf[i] = p->look_buf[i + 1];
    p->look_buf[PARSUNA_K - 1] = pump_token(p);
}

static inline void emit(Parser *p, EvQueued e) {
    uint32_t start;
    switch (e.tag) {
        case EV_ENTER:
        case EV_EXIT:  start = e.pos.offset; break;
        case EV_TOKEN: start = e.token.span.start.offset; break;
        default:       start = e.error.span.start.offset; break;
    }
    flush_skips_before(p, start);
    queue_push(p, e);
}

/* ---------- public driver helpers (called from generated drive()) ---------- */

static inline int get_state(const Parser *p) { return p->state; }
static inline void set_state(Parser *p, int s) { p->state = s; }
static inline void push_ret(Parser *p, int s) { ret_push(p, s); }
static inline int pop_ret(Parser *p) {
    if (p->ret_len > 0) return p->ret[--p->ret_len];
    return TERMINATED;
}
static inline int queue_empty(const Parser *p) { return p->queue_len == 0; }
static inline Token look(const Parser *p, int i) { return p->look_buf[i]; }

static inline int matches_first(const Parser *p, const int *const *set) {
    for (const int *const *seq_p = set; *seq_p != NULL; seq_p++) {
        const int *seq = *seq_p;
        int ok = 1;
        for (int i = 0; seq[i] != SENTINEL; i++) {
            if (p->look_buf[i].kind != seq[i]) { ok = 0; break; }
        }
        if (ok) return 1;
    }
    return 0;
}

static inline void emit_enter(Parser *p, int rule) {
    p->prev_end = p->look_buf[0].span.start;
    EvQueued e = {0};
    e.tag = EV_ENTER;
    e.rule = rule;
    e.pos = p->look_buf[0].span.start;
    emit(p, e);
}

static inline void emit_exit(Parser *p, int rule) {
    EvQueued e = {0};
    e.tag = EV_EXIT;
    e.rule = rule;
    e.pos = p->prev_end;
    emit(p, e);
}

static inline void consume(Parser *p) {
    Token prev = p->look_buf[0];
    p->prev_end = prev.span.end;
    EvQueued e = {0};
    e.tag = EV_TOKEN;
    e.token = prev;
    emit(p, e);
    advance_look(p);
}

static inline void recover_to(Parser *p, const int *sync) {
    while (p->look_buf[0].kind != PARSUNA_EOF_KIND && !set_contains(sync, p->look_buf[0].kind)) {
        EvQueued e = {0};
        e.tag = EV_TOKEN;
        e.token = p->look_buf[0];
        emit(p, e);
        advance_look(p);
    }
}

static inline void error_here(Parser *p, const char *msg) {
    EvQueued e = {0};
    e.tag = EV_ERROR;
    e.error.message = strdup(msg);
    e.error.span.start = p->look_buf[0].span.start;
    e.error.span.end = p->look_buf[0].span.end;
    emit(p, e);
}

static inline void try_consume(Parser *p, int kind, const int *sync, const char *name) {
    if (p->look_buf[0].kind == kind) { consume(p); return; }
    size_t nlen = strlen(name) + 16;
    char *msg = (char*)malloc(nlen);
    snprintf(msg, nlen, "expected %s", name);
    error_here(p, msg);
    free(msg);
    recover_to(p, sync);
    if (p->look_buf[0].kind == kind) consume(p);
}

/* ---------- lifecycle ---------- */

static inline void free_last(Parser *p) {
    /* Borrowed token text is pinned to the caller's buffer — never free it. */
    if (!p->borrow_buf) free(p->last_token.text);
    p->last_token.text = NULL;
    free(p->last_error.message); p->last_error.message = NULL;
}

/* Shared initialization used by both init variants. */
static inline void parser_init_common(Parser *p, int entry_state) {
    p->line = 1;
    p->col = 1;
    p->state = entry_state;
    for (int i = 0; i < PARSUNA_K; i++) p->look_buf[i] = pump_token(p);
    p->prev_end = p->look_buf[0].span.start;
}

/* Initialize `p` for streaming over a `ReadFn` callback. */
static inline void parser_init_from_read_fn(Parser *p,
                                            int entry_state,
                                            ReadFn read_fn,
                                            void *ctx) {
    memset(p, 0, sizeof *p);
    p->read_fn = read_fn;
    p->read_ctx = ctx;
    parser_init_common(p, entry_state);
}

/* Initialize `p` for zero-copy lexing over an in-memory source buffer.
 *
 * The caller keeps ownership of `src`: the parser reads from it directly
 * and every Token's `text` points back into it. `src` must stay live and
 * unmodified until parser_destroy; its contents do not need to be
 * NUL-terminated. */
static inline void parser_init_from_string(Parser *p,
                                           int entry_state,
                                           const char *src,
                                           size_t len) {
    memset(p, 0, sizeof *p);
    /* Cast away const: we never write into the borrowed buffer. The
     * public Token.text is `char *` only for type-compatibility with
     * the reader path. */
    p->buf = (char *)src;
    p->buf_len = len;
    p->buf_cap = len;
    p->eof = 1;
    p->borrow_buf = 1;
    parser_init_common(p, entry_state);
}

static inline int parser_next(Parser *p, Event *out) {
    for (;;) {
        if (p->queue_len > 0) {
            EvQueued q = p->queue[0];
            memmove(p->queue, p->queue + 1, (p->queue_len - 1) * sizeof *p->queue);
            p->queue_len--;
            free_last(p);
            *out = q;
            /* remember strings so caller can read them until next call */
            if (q.tag == EV_TOKEN) p->last_token = q.token;
            if (q.tag == EV_ERROR) p->last_error = q.error;
            return 1;
        }
        if (p->state == TERMINATED) {
            if (!p->eof_checked) {
                p->eof_checked = 1;
                if (p->look_buf[0].kind != PARSUNA_EOF_KIND) {
                    error_here(p, "expected end of input");
                    while (p->look_buf[0].kind != PARSUNA_EOF_KIND) {
                        EvQueued e = {0};
                        e.tag = EV_TOKEN;
                        e.token = p->look_buf[0];
                        emit(p, e);
                        advance_look(p);
                    }
                }
                flush_skips_before(p, p->look_buf[0].span.end.offset);
                continue;
            }
            return 0;
        }
        drive(p);
    }
}

static inline void parser_destroy(Parser *p) {
    if (!p) return;
    if (!p->borrow_buf) free(p->buf);
    free(p->ret);

    for (size_t i = 0; i < p->queue_len; i++) {
        EvQueued *q = &p->queue[i];
        if (q->tag == EV_TOKEN) {
            if (!p->borrow_buf) free(q->token.text);
        } else if (q->tag == EV_ERROR) {
            free(q->error.message);
        }
    }
    free(p->queue);

    if (!p->borrow_buf) {
        for (size_t i = 0; i < p->pending_skips_len; i++) free(p->pending_skips[i].text);
    }
    free(p->pending_skips);

    /* look_buf is an inline fixed-size array — no free. Free each slot's
     * owned text (skipped in borrow mode). */
    if (!p->borrow_buf) {
        for (int i = 0; i < PARSUNA_K; i++) free(p->look_buf[i].text);
    }
    free_last(p);
}

#endif
